   653→func (a *acHandler) Create(ctx context.Context, event event.CreateEvent, q workqueue.TypedRateLimitingInterface[reconcile.Request]) {
   654→	ac, isAc := event.Object.(*kueue.AdmissionCheck)
   655→	if !isAc {
   656→		return
   657→	}
   658→
   659→	if ac.Spec.ControllerName == kueue.ProvisioningRequestControllerName {
   660→		err := a.reconcileWorkloadsUsing(ctx, ac.Name, q)
   661→		if err != nil {
   662→			ctrl.LoggerFrom(ctx).V(5).Error(err, "Failure on create event", "admissionCheck", klog.KObj(ac))
   663→		}
   664→	}
   665→}
   666→
   667→func (a *acHandler) Update(ctx context.Context, event event.UpdateEvent, q workqueue.TypedRateLimitingInterface[reconcile.Request]) {
   668→	oldAc, isOldAc := event.ObjectOld.(*kueue.AdmissionCheck)
   669→	newAc, isNewAc := event.ObjectNew.(*kueue.AdmissionCheck)
   670→	if !isNewAc || !isOldAc {
   671→		return
   672→	}
   673→
   674→	if oldAc.Spec.ControllerName == kueue.ProvisioningRequestControllerName || newAc.Spec.ControllerName == kueue.ProvisioningRequestControllerName {
   675→		err := a.reconcileWorkloadsUsing(ctx, oldAc.Name, q)
   676→		if err != nil {
   677→			ctrl.LoggerFrom(ctx).V(5).Error(err, "Failure on update event", "admissionCheck", klog.KObj(oldAc))
   678→		}
   679→	}
   680→}
   681→
   682→func (a *acHandler) Delete(ctx context.Context, event event.DeleteEvent, q workqueue.TypedRateLimitingInterface[reconcile.Request]) {
   683→	ac, isAc := event.Object.(*kueue.AdmissionCheck)
   684→	if !isAc {
   685→		return
   686→	}
   687→
   688→	if ac.Spec.ControllerName == kueue.ProvisioningRequestControllerName {
   689→		err := a.reconcileWorkloadsUsing(ctx, ac.Name, q)
   690→		if err != nil {
   691→			ctrl.LoggerFrom(ctx).V(5).Error(err, "Failure on delete event", "admissionCheck", klog.KObj(ac))
   692→		}
   693→	}
   694→}
   695→
   696→func (a *acHandler) Generic(_ context.Context, _ event.GenericEvent, _ workqueue.TypedRateLimitingInterface[reconcile.Request]) {
   697→	// nothing to do for now
   698→}
