   753→func (p *prcHandler) Delete(ctx context.Context, event event.DeleteEvent, q workqueue.TypedRateLimitingInterface[reconcile.Request]) {
   754→	prc, isPRC := event.Object.(*kueue.ProvisioningRequestConfig)
