   768→func (p *prcHandler) reconcileWorkloadsUsing(ctx context.Context, config string, q workqueue.TypedRateLimitingInterface[reconcile.Request]) error {
   769→	acs := &kueue.AdmissionCheckList{}
   770→	if err := p.client.List(ctx, acs, client.MatchingFields{AdmissionCheckUsingConfigKey: config}); client.IgnoreNotFound(err) != nil {
   771→		return err
   772→	}
   773→	users := slices.Map(acs.Items, func(ac *kueue.AdmissionCheck) string { return ac.Name })
   774→	for _, user := range users {
   775→		if p.acHandlerOverride != nil {
   776→			if err := p.acHandlerOverride(ctx, user, q); err != nil {
   777→				return err
   778→			}
   779→		} else {
   780→			req := reconcile.Request{
   781→				NamespacedName: types.NamespacedName{
   782→					Name: user,
   783→				},
   784→			}
   785→			q.Add(req)
   786→		}
   787→	}
   788→	return nil
   789→}
