package main

import (
	"fmt"

	"sigs.k8s.io/kueue/pkg/controller/admissionchecks/provisioning"
)

func main() {
	fmt.Println("Final verification after removing deprecated ProvisioningRequest annotations...")

	// Verify deprecated constants are no longer accessible (this should fail to compile if they exist)
	fmt.Printf("ConsumesAnnotationKey: %s\n", provisioning.ConsumesAnnotationKey)
	fmt.Printf("ClassNameAnnotationKey: %s\n", provisioning.ClassNameAnnotationKey)

	// Simulate what happens in podSetUpdates function after our changes
	prName := "test-pr"
	className := "test-class"

	// This should only set the new annotations, not the deprecated ones
	annotations := map[string]string{
		provisioning.ConsumesAnnotationKey:  prName,
		provisioning.ClassNameAnnotationKey: className,
	}

	fmt.Println("\nAnnotations that will be set after our changes:")
	for k, v := range annotations {
		fmt.Printf("  %s: %s\n", k, v)
	}

	// Verify only new annotations are present
	if _, ok := annotations[provisioning.ConsumesAnnotationKey]; ok {
		fmt.Println("\n✓ New consumes annotation is present")
	}

	if _, ok := annotations[provisioning.ClassNameAnnotationKey]; ok {
		fmt.Println("✓ New class name annotation is present")
	}

	// Verify count - should only have 2 annotations instead of 4
	if len(annotations) == 2 {
		fmt.Println("✓ Correct number of annotations (2 instead of 4)")
	} else {
		fmt.Printf("✗ Wrong number of annotations: expected 2, got %d\n", len(annotations))
	}

	fmt.Println("\nSuccessfully deprecated ProvisioningRequest annotations have been removed!")
	fmt.Println("Only the new annotations from autoscaling.x-k8s.io domain will be used.")
}

